+import { describe, it, expect, beforeEach } from 'vitest';
+import {
+  EmailAdapter,
+  InMemoryTransport,
+  escapeHtml,
+  builtInTemplates,
+} from '../../src/adapters/email.adapter.js';
+import type {
+  EmailTransport,
+  RenderedEmail,
+  RecipientResolver,
+  EmailTemplate,
+} from '../../src/adapters/email.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
+  return {
+    id: 'notif-0001',
+    type: 'order-confirmation',
+    channel: 'email',
+    recipient: 'alice@example.com',
+    subject: 'Order Confirmation: order-1',
+    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+    createdAt: new Date('2026-01-01T00:00:00Z'),
+    ...overrides,
+  };
+}
+
+describe('EmailAdapter', () => {
+  let transport: InMemoryTransport;
+  let adapter: EmailAdapter;
+
+  beforeEach(() => {
+    transport = new InMemoryTransport();
+    adapter = new EmailAdapter({ transport });
+  });
+
+  describe('channel', () => {
+    it('should report email channel', () => {
+      expect(adapter.channel).toBe('email');
+    });
+  });
+
+  describe('send', () => {
+    it('should send an email successfully', async () => {
+      const payload = makePayload();
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      expect(result.notificationId).toBe('notif-0001');
+      expect(result.channel).toBe('email');
+      expect(result.deliveredAt).toBeInstanceOf(Date);
+      expect(result.error).toBeUndefined();
+    });
+
+    it('should deliver email via the transport', async () => {
+      const payload = makePayload();
+      await adapter.send(payload);
+
+      const emails = transport.getSentEmails();
+      expect(emails).toHaveLength(1);
+      expect(emails[0]?.to).toBe('alice@example.com');
+      expect(emails[0]?.subject).toBe('Order Confirmation: order-1');
+      expect(emails[0]?.notificationId).toBe('notif-0001');
+    });
+
+    it('should render HTML and text bodies', async () => {
+      const payload = makePayload();
+      await adapter.send(payload);
+
+      const emails = transport.getSentEmails();
+      expect(emails[0]?.html).toContain('<html>');
+      expect(emails[0]?.html).toContain('Order Confirmation');
+      expect(emails[0]?.text).toContain('Order Confirmation');
+      expect(emails[0]?.text).toContain('Widget x2');
+    });
+
+    it('should use order-confirmation template for order confirmations', async () => {
+      const payload = makePayload({ type: 'order-confirmation' });
+      await adapter.send(payload);
+
+      const emails = transport.getSentEmails();
+      expect(emails[0]?.html).toContain('Thank you for your order!');
+      expect(emails[0]?.text).toContain('Thank you for your order!');
+      expect(emails[0]?.html).toContain('We will notify you when your order ships.');
+    });
+
+    it('should use welcome template for welcome notifications', async () => {
+      const payload = makePayload({
+        type: 'welcome',
+        subject: 'Welcome to TaskFlow Pro, Alice!',
+        body: 'Your account has been created.',
+      });
+      await adapter.send(payload);
+
+      const emails = transport.getSentEmails();
+      expect(emails[0]?.html).toContain('Get started by browsing our catalog.');
+      expect(emails[0]?.text).toContain('Get started by browsing our catalog.');
+    });
+
+    it('should use order-status-update template', async () => {
