+        },
+      };
+
+      const failAdapter = new EmailAdapter({ transport: throwingTransport });
+      const payload = makePayload();
+      const result = await failAdapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('Network timeout');
+    });
+
+    it('should handle non-Error throws', async () => {
+      const throwingTransport: EmailTransport = {
+        async sendMail(): Promise<{ success: boolean; error?: string }> {
+          throw 'string error';
+        },
+      };
+
+      const failAdapter = new EmailAdapter({ transport: throwingTransport });
+      const payload = makePayload();
+      const result = await failAdapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('string error');
+    });
+  });
+
+  describe('custom templates', () => {
+    it('should allow overriding built-in templates', async () => {
