/**
 * Email notification adapter — delivers notifications via email.
 *
 * Features:
 * - Template rendering: transforms NotificationPayloads into structured HTML emails
 *   using per-notification-type templates with variable substitution.
 * - Recipient resolution: resolves recipient identifiers (user IDs) to email
 *   addresses via a configurable resolver function.
 * - Configurable transport: accepts an EmailTransport for actual delivery,
 *   defaulting to an in-memory store for testing.
 *
 * Implements NotificationAdapter interface.
 * Adapters handle delivery only — they must NOT subscribe to EventBus directly.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents a rendered email ready for transport.
 */
export interface RenderedEmail {
  to: string;
  subject: string;
  html: string;
  text: string;
  sentAt: Date;
  notificationId: string;
}

/**
 * Transport interface for email delivery.
 * Implement this for real providers (SES, SendGrid, SMTP, etc.).
 */
export interface EmailTransport {
  sendMail(email: RenderedEmail): Promise<{ success: boolean; error?: string }>;
}

/**
 * Resolves a recipient identifier to an email address.
 * For example, converts a userId to the user's email address.
 */
export type RecipientResolver = (recipient: string) => Promise<string | null>;

/**
 * Email template with HTML and text body generators.
 */
export interface EmailTemplate {
  renderHtml(variables: TemplateVariables): string;
  renderText(variables: TemplateVariables): string;
}

export interface TemplateVariables {
  subject: string;
  body: string;
  recipient: string;
  notificationId: string;
  metadata?: Record<string, unknown>;
}

/**
 * Configuration for the EmailAdapter.
 */
export interface EmailAdapterConfig {
  transport?: EmailTransport;
  recipientResolver?: RecipientResolver;
  templates?: Partial<Record<NotificationType, EmailTemplate>>;
  fromAddress?: string;
}

/**
 * Default in-memory transport for testing.
 */
export class InMemoryTransport implements EmailTransport {
  private sentEmails: RenderedEmail[] = [];

  async sendMail(email: RenderedEmail): Promise<{ success: boolean; error?: string }> {
    this.sentEmails.push(email);
    return { success: true };
  }

  getSentEmails(): RenderedEmail[] {
    return [...this.sentEmails];
  }

  clear(): void {
    this.sentEmails = [];
  }
}

/**
 * Default email template used when no notification-type-specific template is registered.
 */
const defaultTemplate: EmailTemplate = {
  renderHtml(variables: TemplateVariables): string {
    return [
      '<!DOCTYPE html>',
      '<html>',
      '<head><meta charset="utf-8"></head>',
      '<body>',
      `<h1>${escapeHtml(variables.subject)}</h1>`,
      `<p>${escapeHtml(variables.body)}</p>`,
      '<hr>',
      '<p style="color: #666; font-size: 12px;">This is an automated notification from TaskFlow Pro.</p>',
      '</body>',
      '</html>',
    ].join('\n');
  },
  renderText(variables: TemplateVariables): string {
    return `${variables.subject}\n\n${variables.body}\n\n---\nThis is an automated notification from TaskFlow Pro.`;
  },
};

/**
 * Built-in templates for each notification type.
 */
const builtInTemplates: Record<NotificationType, EmailTemplate> = {
  'order-confirmation': {
    renderHtml(variables: TemplateVariables): string {
      return [
        '<!DOCTYPE html>',
        '<html>',
        '<head><meta charset="utf-8"></head>',
        '<body>',
        '<h1>Order Confirmation</h1>',
        `<p>Thank you for your order!</p>`,
        `<div>${escapeHtml(variables.body)}</div>`,
        '<p>We will notify you when your order ships.</p>',
        '<hr>',
        '<p style="color: #666; font-size: 12px;">TaskFlow Pro - Order Management</p>',
        '</body>',
        '</html>',
      ].join('\n');
    },
    renderText(variables: TemplateVariables): string {
      return `Order Confirmation\n\nThank you for your order!\n\n${variables.body}\n\nWe will notify you when your order ships.\n\n---\nTaskFlow Pro - Order Management`;
    },
  },
  'order-status-update': {
    renderHtml(variables: TemplateVariables): string {
      return [
        '<!DOCTYPE html>',
        '<html>',
        '<head><meta charset="utf-8"></head>',
        '<body>',
        '<h1>Order Status Update</h1>',
        `<p>${escapeHtml(variables.body)}</p>`,
        '<p>Log in to your account for full details.</p>',
        '<hr>',
        '<p style="color: #666; font-size: 12px;">TaskFlow Pro - Order Management</p>',
        '</body>',
        '</html>',
      ].join('\n');
    },
    renderText(variables: TemplateVariables): string {
      return `Order Status Update\n\n${variables.body}\n\nLog in to your account for full details.\n\n---\nTaskFlow Pro - Order Management`;
    },
  },
  'welcome': {
    renderHtml(variables: TemplateVariables): string {
      return [
        '<!DOCTYPE html>',
        '<html>',
        '<head><meta charset="utf-8"></head>',
        '<body>',
        `<h1>${escapeHtml(variables.subject)}</h1>`,
        `<p>${escapeHtml(variables.body)}</p>`,
        '<p>Get started by browsing our catalog.</p>',
        '<hr>',
        '<p style="color: #666; font-size: 12px;">TaskFlow Pro</p>',
        '</body>',
        '</html>',
      ].join('\n');
    },
    renderText(variables: TemplateVariables): string {
      return `${variables.subject}\n\n${variables.body}\n\nGet started by browsing our catalog.\n\n---\nTaskFlow Pro`;
    },
  },
  'user-updated': {
    renderHtml(variables: TemplateVariables): string {
      return [
        '<!DOCTYPE html>',
        '<html>',
        '<head><meta charset="utf-8"></head>',
        '<body>',
        '<h1>Account Updated</h1>',
        `<p>${escapeHtml(variables.body)}</p>`,
        '<p>If you did not make these changes, please contact support immediately.</p>',
        '<hr>',
        '<p style="color: #666; font-size: 12px;">TaskFlow Pro - Account Security</p>',
        '</body>',
        '</html>',
      ].join('\n');
    },
    renderText(variables: TemplateVariables): string {
      return `Account Updated\n\n${variables.body}\n\nIf you did not make these changes, please contact support immediately.\n\n---\nTaskFlow Pro - Account Security`;
    },
  },
};

/**
 * Escape HTML special characters to prevent XSS in email templates.
 */
function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#x27;');
}

/**
 * Default recipient resolver — treats the recipient as an email address if it
 * contains '@', otherwise returns null (unresolvable).
 */
const defaultRecipientResolver: RecipientResolver = async (recipient: string) => {
  if (recipient.includes('@')) {
    return recipient;
  }
  return null;
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private transport: EmailTransport;
  private recipientResolver: RecipientResolver;
  private templates: Map<NotificationType, EmailTemplate>;

  constructor(config: EmailAdapterConfig = {}) {
    this.transport = config.transport ?? new InMemoryTransport();
    this.recipientResolver = config.recipientResolver ?? defaultRecipientResolver;

    // Merge built-in templates with any overrides
    this.templates = new Map<NotificationType, EmailTemplate>();
    for (const [type, template] of Object.entries(builtInTemplates)) {
      this.templates.set(type as NotificationType, template);
    }
    if (config.templates) {
      for (const [type, template] of Object.entries(config.templates)) {
        if (template) {
          this.templates.set(type as NotificationType, template);
        }
      }
    }
  }

  /**
   * Send a notification via email.
   * 1. Resolves recipient to an email address.
   * 2. Renders the email using the appropriate template.
   * 3. Delivers via the configured transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const resolvedRecipient = await this.resolveRecipient(payload.recipient);
    if (!resolvedRecipient) {
      this.logger.warn(`Could not resolve recipient: ${payload.recipient}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: `Could not resolve recipient: ${payload.recipient}`,
        deliveredAt: new Date(),
      };
    }

    const variables: TemplateVariables = {
      subject: payload.subject,
      body: payload.body,
      recipient: resolvedRecipient,
      notificationId: payload.id,
      metadata: payload.metadata,
    };

    const template = this.templates.get(payload.type) ?? defaultTemplate;

    const renderedEmail: RenderedEmail = {
      to: resolvedRecipient,
      subject: payload.subject,
      html: template.renderHtml(variables),
      text: template.renderText(variables),
      sentAt: new Date(),
      notificationId: payload.id,
    };

    this.logger.info(`Sending email to ${resolvedRecipient}: ${payload.subject}`);

    try {
      const result = await this.transport.sendMail(renderedEmail);

      if (!result.success) {
        this.logger.error(`Transport failed for ${payload.id}: ${result.error}`);
        return {
          success: false,
          notificationId: payload.id,
          channel: this.channel,
          error: result.error ?? 'Transport delivery failed',
          deliveredAt: new Date(),
        };
      }

      return {
        success: true,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: renderedEmail.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Transport error for ${payload.id}: ${errorMessage}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Resolve a recipient identifier to an email address.
   */
  private async resolveRecipient(recipient: string): Promise<string | null> {
    return this.recipientResolver(recipient);
  }

  /**
   * Get the transport (useful for testing with InMemoryTransport).
   */
  getTransport(): EmailTransport {
    return this.transport;
  }
}

export { escapeHtml, defaultTemplate, builtInTemplates };

