import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
  escapeHtml,
  builtInTemplates,
} from '../../src/adapters/email.adapter.js';
import type {
  EmailTransport,
  RenderedEmail,
  RecipientResolver,
  EmailTemplate,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    createdAt: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let transport: InMemoryTransport;
  let adapter: EmailAdapter;

  beforeEach(() => {
    transport = new InMemoryTransport();
    adapter = new EmailAdapter({ transport });
  });

  describe('channel', () => {
    it('should report email channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('send', () => {
    it('should send an email successfully', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should deliver email via the transport', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toBe('Order Confirmation: order-1');
      expect(emails[0]?.notificationId).toBe('notif-0001');
    });

    it('should render HTML and text bodies', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails[0]?.html).toContain('<html>');
      expect(emails[0]?.html).toContain('Order Confirmation');
      expect(emails[0]?.text).toContain('Order Confirmation');
      expect(emails[0]?.text).toContain('Widget x2');
    });

    it('should use order-confirmation template for order confirmations', async () => {
      const payload = makePayload({ type: 'order-confirmation' });
      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails[0]?.html).toContain('Thank you for your order!');
      expect(emails[0]?.text).toContain('Thank you for your order!');
      expect(emails[0]?.html).toContain('We will notify you when your order ships.');
    });

    it('should use welcome template for welcome notifications', async () => {
      const payload = makePayload({
        type: 'welcome',
        subject: 'Welcome to TaskFlow Pro, Alice!',
        body: 'Your account has been created.',
      });
      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails[0]?.html).toContain('Get started by browsing our catalog.');
      expect(emails[0]?.text).toContain('Get started by browsing our catalog.');
    });

    it('should use order-status-update template', async () => {
      const payload = makePayload({
        type: 'order-status-update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
      });
      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails[0]?.html).toContain('Order Status Update');
      expect(emails[0]?.html).toContain('Log in to your account for full details.');
    });

    it('should use user-updated template', async () => {
      const payload = makePayload({
        type: 'user-updated',
        subject: 'Account Updated',
        body: 'Your profile has been updated.',
      });
      await adapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails[0]?.html).toContain('Account Updated');
      expect(emails[0]?.html).toContain('contact support immediately');
    });
  });

  describe('recipient resolution', () => {
    it('should resolve email addresses directly', async () => {
      const payload = makePayload({ recipient: 'bob@example.com' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(transport.getSentEmails()[0]?.to).toBe('bob@example.com');
    });

    it('should fail for unresolvable recipients (no @ sign)', async () => {
      const payload = makePayload({ recipient: 'user-123' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Could not resolve recipient');
      expect(result.error).toContain('user-123');
      expect(transport.getSentEmails()).toHaveLength(0);
    });

    it('should use custom recipient resolver', async () => {
      const resolver: RecipientResolver = async (recipient) => {
        if (recipient === 'user-1') return 'alice@example.com';
        if (recipient === 'user-2') return 'bob@example.com';
        return null;
      };

      const adapterWithResolver = new EmailAdapter({ transport, recipientResolver: resolver });
      const payload = makePayload({ recipient: 'user-1' });
      const result = await adapterWithResolver.send(payload);

      expect(result.success).toBe(true);
      expect(transport.getSentEmails()[0]?.to).toBe('alice@example.com');
    });

    it('should fail when custom resolver returns null', async () => {
      const resolver: RecipientResolver = async () => null;
      const adapterWithResolver = new EmailAdapter({ transport, recipientResolver: resolver });
      const payload = makePayload({ recipient: 'unknown-user' });
      const result = await adapterWithResolver.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Could not resolve recipient');
    });
  });

  describe('transport errors', () => {
    it('should handle transport returning failure', async () => {
      const failingTransport: EmailTransport = {
        async sendMail(): Promise<{ success: boolean; error?: string }> {
          return { success: false, error: 'SMTP connection refused' };
        },
      };

      const failAdapter = new EmailAdapter({ transport: failingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });

    it('should handle transport throwing an exception', async () => {
      const throwingTransport: EmailTransport = {
        async sendMail(): Promise<{ success: boolean; error?: string }> {
          throw new Error('Network timeout');
        },
      };

      const failAdapter = new EmailAdapter({ transport: throwingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Network timeout');
    });

    it('should handle non-Error throws', async () => {
      const throwingTransport: EmailTransport = {
        async sendMail(): Promise<{ success: boolean; error?: string }> {
          throw 'string error';
        },
      };

      const failAdapter = new EmailAdapter({ transport: throwingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('string error');
    });
  });

  describe('custom templates', () => {
    it('should allow overriding built-in templates', async () => {
      const customTemplate: EmailTemplate = {
        renderHtml: (vars) => `<custom>${vars.body}</custom>`,
        renderText: (vars) => `CUSTOM: ${vars.body}`,
      };

      const customAdapter = new EmailAdapter({
        transport,
        templates: { 'order-confirmation': customTemplate },
      });

      const payload = makePayload({ type: 'order-confirmation' });
      await customAdapter.send(payload);

      const emails = transport.getSentEmails();
      expect(emails[0]?.html).toBe(`<custom>${payload.body}</custom>`);
      expect(emails[0]?.text).toBe(`CUSTOM: ${payload.body}`);
    });

    it('should still use built-in templates for non-overridden types', async () => {
      const customTemplate: EmailTemplate = {
        renderHtml: (vars) => `<custom>${vars.body}</custom>`,
        renderText: (vars) => `CUSTOM: ${vars.body}`,
      };

      const customAdapter = new EmailAdapter({
        transport,
        templates: { 'order-confirmation': customTemplate },
      });

      const payload = makePayload({ type: 'welcome', subject: 'Welcome!', body: 'Hi there' });
      await customAdapter.send(payload);

      const emails = transport.getSentEmails();
      // Should use the built-in welcome template, not the custom one
      expect(emails[0]?.html).toContain('Get started by browsing our catalog.');
    });
  });

  describe('getTransport', () => {
    it('should return the configured transport', () => {
      expect(adapter.getTransport()).toBe(transport);
    });

    it('should default to InMemoryTransport', () => {
      const defaultAdapter = new EmailAdapter();
      expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemoryTransport);
    });
  });
});

describe('InMemoryTransport', () => {
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
  });

  it('should store sent emails', async () => {
    const email: RenderedEmail = {
      to: 'test@example.com',
      subject: 'Test',
      html: '<p>Test</p>',
      text: 'Test',
      sentAt: new Date(),
      notificationId: 'notif-1',
    };

    const result = await transport.sendMail(email);
    expect(result.success).toBe(true);
    expect(transport.getSentEmails()).toHaveLength(1);
    expect(transport.getSentEmails()[0]?.to).toBe('test@example.com');
  });

  it('should clear sent emails', async () => {
    const email: RenderedEmail = {
      to: 'test@example.com',
      subject: 'Test',
      html: '<p>Test</p>',
      text: 'Test',
      sentAt: new Date(),
      notificationId: 'notif-1',
    };

    await transport.sendMail(email);
    transport.clear();
    expect(transport.getSentEmails()).toHaveLength(0);
  });
});

describe('escapeHtml', () => {
  it('should escape ampersands', () => {
    expect(escapeHtml('a & b')).toBe('a &amp; b');
  });

  it('should escape angle brackets', () => {
    expect(escapeHtml('<script>alert("xss")</script>')).toBe(
      '&lt;script&gt;alert(&quot;xss&quot;)&lt;/script&gt;',
    );
  });

  it('should escape quotes', () => {
    expect(escapeHtml("it's \"quoted\"")).toBe("it&#x27;s &quot;quoted&quot;");
  });

  it('should handle empty strings', () => {
    expect(escapeHtml('')).toBe('');
  });
});

describe('builtInTemplates', () => {
  it('should have templates for all notification types', () => {
    expect(builtInTemplates['order-confirmation']).toBeDefined();
